// lib/bench-docs.ts -- custom SSM documents for the three bench commands.
//
// Each document is schemaVersion 2.2 (the modern shell-runner schema) and
// uploads its artifact to the results S3 bucket after the script exits.
// Document NAMES are auto-generated by CloudFormation (no hardcoded
// names), which avoids the SSM "document name globally unique within
// account+region" collision when redeploying the stack.
//
// The runCommand arrays MUST be lists of single-line shell strings; SSM
// joins them with newlines and runs the result as one /bin/bash session.
import { Construct } from 'constructs';
import * as ssm from 'aws-cdk-lib/aws-ssm';

export interface BenchDocumentsProps {
  readonly resultsBucketName: string;
  readonly region: string;
}

export class BenchDocuments extends Construct {
  public readonly profileDoc: ssm.CfnDocument;
  public readonly sweepDoc: ssm.CfnDocument;
  public readonly benchDoc: ssm.CfnDocument;

  public readonly profileDocName: string;
  public readonly sweepDocName: string;
  public readonly benchDocName: string;

  constructor(scope: Construct, id: string, props: BenchDocumentsProps) {
    super(scope, id);

    this.profileDoc = new ssm.CfnDocument(this, 'ProfileDoc', {
      documentType: 'Command',
      documentFormat: 'JSON',
      content: profileContent(props.resultsBucketName),
      tags: [{ key: 'Project', value: 'pulsys' }, { key: 'Doc', value: 'profile' }],
    });
    this.profileDocName = this.profileDoc.ref;

    this.sweepDoc = new ssm.CfnDocument(this, 'SweepDoc', {
      documentType: 'Command',
      documentFormat: 'JSON',
      content: sweepContent(props.resultsBucketName),
      tags: [{ key: 'Project', value: 'pulsys' }, { key: 'Doc', value: 'sweep' }],
    });
    this.sweepDocName = this.sweepDoc.ref;

    // The bench doc IS the full-machine pulsys benchmark.  There is no
    // separate "saturate" doc; this is the only EC2 chart we publish.
    this.benchDoc = new ssm.CfnDocument(this, 'BenchDoc', {
      documentType: 'Command',
      documentFormat: 'JSON',
      content: benchContent(props.resultsBucketName),
      tags: [{ key: 'Project', value: 'pulsys' }, { key: 'Doc', value: 'bench' }],
    });
    this.benchDocName = this.benchDoc.ref;
  }
}

// SSM runShellScript sessions are non-login shells; source the AMI env
// so `go build` in bench_matrix.sh sees GOMODCACHE/GOPATH.
const SSM_ENV_PREFIX: string[] = [
  'set -euo pipefail',
  'export HOME=/root',
  'source /etc/profile.d/pulsys-go.sh 2>/dev/null || true',
  'export PATH=/usr/local/go/bin:/opt/go/bin:${PATH}',
  'export GOPATH=/opt/go',
  'export GOMODCACHE=${GOMODCACHE:-/opt/go/pkg/mod}',
  'export GOCACHE=${GOCACHE:-/opt/go/cache}',
  'mkdir -p /opt/go/cache /opt/go/pkg/mod',
];

// -----------------------------------------------------------------------
// Document contents.  Each runShellScript step:
//   1. sets env vars from SSM parameters,
//   2. cd's into the AMI's pre-baked repo at /opt/pulsys-src,
//   3. runs the harness script and tees output to /var/log/pulsys/,
//   4. extracts the artifact path from the last line (the harness scripts
//      print PROFILE_ARTIFACT= / SWEEP_ARTIFACT= as their final stdout),
//   5. uploads to s3://<bucket>/<prefix>/ for download by ssm-*.sh.
// -----------------------------------------------------------------------

function profileContent(bucket: string): object {
  return {
    schemaVersion: '2.2',
    description:
      'Run pulsys profile_baseline.sh on the instance and upload the artifact tarball to S3',
    parameters: {
      duration: { type: 'String', description: 'wrk run duration in seconds', default: '60' },
      conns: { type: 'String', description: 'wrk concurrent connections', default: '384' },
      threads: {
        type: 'String',
        description: 'wrk -t (max = vCPU, auto = min(CONNS, vCPU/2))',
        default: 'max',
      },
      payload: { type: 'String', description: 'warm payload (4k|64k|256k|4m|16m)', default: '4k' },
      variant: {
        type: 'String',
        description:
          'pulsys shape: saturate-no-cork (default) | saturate | saturate-iouring | …',
        default: 'saturate-no-cork',
      },
      roundTag: { type: 'String', description: 'artifact dir tag', default: 'saturate-no-cork' },
    },
    mainSteps: [
      {
        action: 'aws:runShellScript',
        name: 'profile',
        inputs: {
          runCommand: [
            ...SSM_ENV_PREFIX,
            'mkdir -p /var/log/pulsys',
            'export DURATION={{duration}}',
            'export CONNS={{conns}}',
            'export THREADS={{threads}}',
            'export PAYLOAD={{payload}}',
            'export PULSYS_VARIANT={{variant}}',
            'export ROUND_TAG={{roundTag}}',
            'cd /opt/pulsys-src',
            'bash scripts/profile_baseline.sh 2>&1 | tee /var/log/pulsys/profile.last.log',
            'ART=$(grep "^PROFILE_ARTIFACT=" /var/log/pulsys/profile.last.log | tail -1 | cut -d= -f2-)',
            'if [ -z "$ART" ]; then echo "FATAL: no PROFILE_ARTIFACT marker in output" >&2; exit 1; fi',
            `aws s3 cp "$ART" s3://${bucket}/profile/ --no-progress`,
            'echo "uploaded $(basename $ART) to s3://' + bucket + '/profile/"',
          ],
        },
      },
    ],
  };
}

function sweepContent(bucket: string): object {
  return {
    schemaVersion: '2.2',
    description:
      'Run pulsys sweep_tunings.sh on the instance and upload sweep tarball + report to S3',
    parameters: {
      duration: { type: 'String', default: '30' },
      rounds: { type: 'String', default: '3' },
      conns: {
        type: 'String',
        description: 'space-separated concurrency levels',
        default: '64 256',
      },
      payloads: {
        type: 'String',
        description: 'space-separated payload labels',
        default: '4k 256k 16m',
      },
      only: {
        type: 'String',
        description: 'comma-separated subset of tuning names (empty = all)',
        default: '',
      },
    },
    mainSteps: [
      {
        action: 'aws:runShellScript',
        name: 'sweep',
        inputs: {
          runCommand: [
            ...SSM_ENV_PREFIX,
            'mkdir -p /var/log/pulsys',
            'export DURATION={{duration}}',
            'export ROUNDS={{rounds}}',
            'export CONNS="{{conns}}"',
            'export PAYLOADS="{{payloads}}"',
            'export ONLY="{{only}}"',
            'cd /opt/pulsys-src',
            'bash scripts/sweep_tunings.sh 2>&1 | tee /var/log/pulsys/sweep.last.log',
            'ART=$(grep "^SWEEP_ARTIFACT=" /var/log/pulsys/sweep.last.log | tail -1 | cut -d= -f2-)',
            'REPORT=$(grep "^SWEEP_REPORT=" /var/log/pulsys/sweep.last.log | tail -1 | cut -d= -f2-)',
            'if [ -z "$ART" ]; then echo "FATAL: no SWEEP_ARTIFACT marker in output" >&2; exit 1; fi',
            `aws s3 cp "$ART" s3://${bucket}/sweep/ --no-progress`,
            `[ -n "$REPORT" ] && aws s3 cp "$REPORT" s3://${bucket}/sweep/ --no-progress || true`,
            'echo "uploaded sweep artifact $(basename $ART) to s3://' + bucket + '/sweep/"',
          ],
        },
      },
    ],
  };
}

function benchContent(bucket: string): object {
  return {
    schemaVersion: '2.2',
    description:
      'Run pulsys bench_saturate.sh on the instance (full-machine, pulsys alone) and upload report + charts to S3.',
    parameters: {
      duration: { type: 'String', default: '30s' },
      conns: {
        type: 'String',
        description: 'wrk -c (empty = 4 * vCPU)',
        default: '',
      },
      payloads: { type: 'String', default: '4k 256k 4m 16m' },
      rounds: { type: 'String', default: '3' },
      variant: {
        type: 'String',
        description:
          'server shape: saturate-no-cork (default) | saturate | saturate-iouring',
        default: 'saturate-no-cork',
      },
    },
    mainSteps: [
      {
        action: 'aws:runShellScript',
        name: 'bench',
        inputs: {
          runCommand: [
            ...SSM_ENV_PREFIX,
            'mkdir -p /var/log/pulsys',
            'cd /opt/pulsys-src',
            '[ -n "{{conns}}" ] && export CONNS="{{conns}}"',
            'export PAYLOADS="{{payloads}}"',
            'export ROUNDS="{{rounds}}"',
            'export SATURATE_VARIANT="{{variant}}"',
            'bash scripts/bench_saturate.sh "{{duration}}" 2>&1 | tee /var/log/pulsys/bench.last.log',
            'TS=$(date -u +%Y%m%dT%H%M%SZ)',
            'KEY_PREFIX="bench/${TS}-{{variant}}"',
            'CHART_PREFIX="charts/${TS}-{{variant}}"',
            'mkdir -p tmp/bench/ec2 docs/results/ec2',
            'cp tmp/bench/matrix.csv tmp/bench/ec2/matrix.csv',
            'cp tmp/bench/saturate-report.md tmp/bench/ec2/report.md 2>/dev/null || true',
            'cp tmp/bench/headline.json tmp/bench/ec2/headline.json 2>/dev/null || true',
            'BENCH_PLATFORM=ec2 bash scripts/bench_write_meta.sh ec2 tmp/bench/ec2',
            'SATURATE_MATRIX=tmp/bench/ec2/matrix.csv SATURATE_CHARTS_DIR=docs/results/ec2 go run scripts/render_saturate_charts.go',
            `aws s3 cp tmp/bench/ec2/matrix.csv "s3://${bucket}/$KEY_PREFIX/matrix.csv" --no-progress`,
            `aws s3 cp tmp/bench/ec2/matrix.meta.json "s3://${bucket}/$KEY_PREFIX/matrix.meta.json" --no-progress`,
            `[ -f tmp/bench/ec2/report.md ] && aws s3 cp tmp/bench/ec2/report.md "s3://${bucket}/$KEY_PREFIX/report.md" --no-progress || true`,
            `[ -f tmp/bench/ec2/headline.json ] && aws s3 cp tmp/bench/ec2/headline.json "s3://${bucket}/$KEY_PREFIX/headline.json" --no-progress || true`,
            'for f in docs/results/ec2/*.svg; do',
            '  [ -f "$f" ] || continue',
            `  aws s3 cp "$f" "s3://${bucket}/$CHART_PREFIX/" --no-progress`,
            'done',
            'ART=$(grep "^SATURATE_ARTIFACT=" /var/log/pulsys/bench.last.log | tail -1 | cut -d= -f2-)',
            `[ -n "$ART" ] && aws s3 cp "$ART" "s3://${bucket}/$KEY_PREFIX/" --no-progress || true`,
            `echo "uploaded matrix + report to s3://${bucket}/$KEY_PREFIX/"`,
            `echo "uploaded charts to s3://${bucket}/$CHART_PREFIX/"`,
          ],
        },
      },
    ],
  };
}
